INSERT INTO terms (id, term, term_ja, chapter_id, order_index, difficulty, one_liner, definition, mechanism, analogy, pitfall, related_terms, story_context)
VALUES
  ('syntax', 'Syntax', 'シンタックス', 4, 1, 1, 'プログラミング言語の文法ルール', 'プログラミング言語の書き方のルール。どのような順序で、どのような記号を使って命令を書くかを定めたもの。', 'Syntaxに従わないコードはシンタックスエラー（文法エラー）となり、実行できない。言語ごとにSyntaxは異なる。', '言語の文法。日本語なら「主語＋目的語＋動詞」、英語なら「主語＋動詞＋目的語」のような語順ルール。', 'セミコロン忘れ、括弧の閉じ忘れなど、小さなミスでエラーになる。エラーメッセージをよく読んで場所を特定する。', ARRAY['statement', 'expression', 'error'], '道場に入ってすぐ。「まず、Syntax（シンタックス・構文）から」とループちゃんが筆で書く。'),
  ('statement', 'Statement', '文', 4, 2, 1, '実行される命令の1単位', 'プログラムを構成する命令の1単位。変数宣言、代入、条件分岐、ループなど、実行される処理のひとかたまり。', 'let x = 10; や if (条件) { ... } のように、セミコロンや波括弧で区切られる。上から順に実行される。', '文章の「一文」。「私は走る。」「彼は食べる。」のように、意味を持つ最小の命令単位。', '式（expression）と文（statement）の違いがわかりにくい。式は値を返し、文は処理を実行する。', ARRAY['expression', 'syntax', 'line'], '「Statement（文）は、命令の1文」と説明。図で let x = 5 + 3; の構造を示す。'),
  ('expression', 'Expression', '式', 4, 3, 1, '値を生み出す計算式', '評価されて値を返すコードの断片。数式、関数呼び出し、変数参照などが式に当たる。', '5 + 3 は 8 を返す式。x > 10 は true または false を返す式。式は文の一部として使われることが多い。', '数学の式。「2 + 3」は計算すると「5」という答え（値）が出る。', 'x = 5 は代入文だが、= の右側の 5 は式。文と式が混在していることを意識する。', ARRAY['statement', 'operator', 'value'], '「Expression（式）は、値を生み出す部分です」と図の中の 5 + 3 の部分を指す。'),
  ('operator', 'Operator', '演算子', 4, 4, 1, '計算や比較を行う記号', '値に対して操作を行う記号。算術演算子（+, -, *, /）、比較演算子（===, <, >）、論理演算子（&&, ||）などがある。', 'a + b なら + が演算子、a と b がオペランド（被演算子）。演算子は優先順位があり、* は + より先に計算される。', '電卓の「+」「-」「×」「÷」ボタン。数字（オペランド）に対して操作を行う。', '= と == と === の違いに注意。= は代入、== は緩い等価、=== は厳密等価。JavaScriptでは基本 === を使う。', ARRAY['expression', 'comparison-operator', 'logical-operator'], '「Operator（演算子）は、+、-、×、÷のような記号。計算や比較を行います」'),
  ('assignment', 'Assignment', '代入', 4, 5, 1, '変数に値を入れる操作', '変数に値を格納する操作。= 記号を使って、右辺の値を左辺の変数に入れる。', 'let x = 10; は「xに10を代入」。x = x + 1; は「xの現在値に1を足した結果をxに再代入」。', '箱にラベルを貼って、中にものを入れる行為。「りんご箱」に「りんご」を入れる。', '数学の = とは意味が違う。プログラムの = は「等しい」ではなく「入れる」という意味。', ARRAY['variable', 'operator', 'declaration'], '「= は Assignment（代入）。右側の値を、左側の変数に入れる、という意味です」'),
  ('declaration', 'Declaration', '宣言', 4, 6, 1, '変数や関数を新しく作ること', '変数や関数を新しく定義すること。let、const、function などのキーワードを使って「これを使います」と宣言する。', 'let x; は「xという変数を宣言」。function greet() {} は「greetという関数を宣言」。宣言後に使用可能になる。', '新入社員の紹介。「今日から山田さんが入ります」と宣言して、初めてその人が会社で働ける。', '宣言と代入は別。let x; は宣言のみ、let x = 10; は宣言と代入を同時に行っている。', ARRAY['variable', 'assignment', 'function'], '「宣言」の概念説明。「変数を使う前に、まず『宣言』が必要です」'),
  ('function', 'Function', '関数', 4, 7, 1, '処理をまとめて名前をつけたもの', '一連の処理をまとめて名前をつけ、何度でも呼び出せるようにしたもの。引数を受け取り、戻り値を返すことができる。', 'function 名前(引数) { 処理 return 結果; } の形で定義。名前() で呼び出す。コードの再利用性を高める。', '料理のレシピ。「カレーの作り方」をレシピ（関数）として保存しておけば、いつでも同じ手順で作れる。', '関数の中で関数を呼ぶこともできる（再帰）。ただし無限ループに注意。', ARRAY['method', 'parameter', 'return-value'], '「プログラミングの必殺技、Function（関数）を教えましょう」とループちゃんがコード例を見せる。'),
  ('method', 'Method', 'メソッド', 4, 8, 1, 'オブジェクトに属する関数', 'オブジェクトのプロパティとして定義された関数。オブジェクト.メソッド名() の形で呼び出す。', 'const obj = { greet: function() { return "Hello"; } }; なら obj.greet() で呼び出す。配列の push() や文字列の toUpperCase() もメソッド。', '人間が持つ「技能」。「田中さん.料理する()」「田中さん.走る()」のように、その人（オブジェクト）ができること。', '関数とメソッドは似ているが、メソッドは必ずオブジェクトに紐づいている。this の扱いも異なる。', ARRAY['function', 'object', 'this-keyword'], '「Method（メソッド）は、オブジェクトに属する関数のことです」'),
  ('parameter', 'Parameter', 'パラメータ', 4, 9, 1, '関数が受け取る値の受け皿', '関数定義時に指定する、値を受け取るための変数。仮引数とも呼ばれる。関数が呼び出されたときに実際の値（引数）が渡される。', 'function greet(name) { ... } の name がパラメータ。関数内で name という名前で渡された値を使える。', '注文書の空欄。「お名前：＿＿＿」という空欄（パラメータ）に、実際の名前（引数）を書き込む。', '「パラメータ」と「引数（Argument）」は混同されやすい。パラメータは定義側、引数は呼び出し側。', ARRAY['argument', 'function', 'return-value'], '「Parameter は、関数を作るときに用意する『受け取り口』」'),
  ('parameters', 'Parameters', 'パラメータ（複数）', 4, 10, 1, '関数が受け取る複数の値の受け皿', '関数が複数の値を受け取る場合の、それぞれの受け皿。カンマで区切って複数定義できる。', 'function add(a, b) { return a + b; } の a と b が parameters。順番に対応する引数が渡される。', '注文書の複数の空欄。「お名前：＿＿＿」「ご住所：＿＿＿」「電話番号：＿＿＿」とそれぞれに記入。', '引数の数とパラメータの数が合わないとエラーや undefined になることがある。', ARRAY['parameter', 'argument', 'function'], '複数のパラメータを持つ関数の例を説明。'),
  ('argument', 'Argument', '引数', 4, 11, 1, '関数を呼び出すときに渡す実際の値', '関数を呼び出すときに実際に渡す値。実引数とも呼ばれる。パラメータに対応して渡される。', 'greet("ビットくん") の "ビットくん" が引数。関数内では対応するパラメータ名で参照できる。', '注文書に実際に書き込む内容。空欄（パラメータ）に「山田太郎」（引数）と書く。', '引数の順番を間違えると意図しない動作になる。名前で渡せる言語もある（キーワード引数）。', ARRAY['parameter', 'function'], '「Argument（引数）は、関数を使うときに渡す『実際の値』」と図で示す。'),
  ('return-value', 'Return value', '戻り値', 4, 12, 1, '関数が返してくれる結果', '関数の処理結果として呼び出し元に返される値。return 文で指定する。', 'function add(a, b) { return a + b; } なら、add(2, 3) は 5 を返す。return がないと undefined が返る。', '自動販売機のお釣りと商品。お金（引数）を入れて、商品（戻り値）が出てくる。', 'return を忘れると undefined が返る。また、return 後のコードは実行されない。', ARRAY['function', 'parameter', 'argument'], '「Return value（戻り値）は、関数が返してくれる結果です」'),
  ('scope', 'Scope', 'スコープ', 4, 13, 2, '変数が見える・使える範囲', '変数やが参照できる範囲のこと。スコープ外からは変数にアクセスできない。', '変数は宣言された場所によってアクセスできる範囲が決まる。関数内で宣言した変数は関数外からは見えない。', '学校の教室。教室（スコープ）の中でしか先生の声（変数）は聞こえない。隣の教室には届かない。', '同じ名前の変数がスコープごとに存在できる。どの変数を参照しているか意識する必要がある。', ARRAY['local-scope', 'global-scope', 'block-scope'], '「Scope（スコープ）は、変数が見える範囲のことです」とループちゃんが図を描く。'),
  ('local-scope', 'Local scope', 'ローカルスコープ', 4, 14, 2, '関数の中だけで見える範囲', '関数内で宣言された変数が有効な範囲。その関数の中でだけアクセスできる。', 'function test() { let local = 1; } の local は test 関数の中でしか使えない。外から参照するとエラー。', '自分の部屋の本棚。部屋（関数）の中にある本（変数）は、部屋の外からは取れない。', 'ローカル変数は関数が終わると消える。保持したい場合はクロージャを使う。', ARRAY['scope', 'global-scope', 'closure'], '「Local scope は、関数の中だけで見える範囲」'),
  ('global-scope', 'Global scope', 'グローバルスコープ', 4, 15, 2, 'プログラム全体から見える範囲', 'どこからでもアクセスできる最も外側のスコープ。グローバルスコープで宣言された変数はどこからでも参照できる。', '関数の外で宣言された変数はグローバル変数になる。便利だが、意図しない変更のリスクがある。', '学校の放送。全教室（すべてのスコープ）に聞こえる。便利だが、プライベートな話はできない。', 'グローバル変数の多用は避ける。どこからでも変更できるため、バグの原因になりやすい。', ARRAY['scope', 'local-scope', 'variable'], '「Global scope は、プログラム全体から見える範囲」'),
  ('block-scope', 'Block scope', 'ブロックスコープ', 4, 16, 2, '{ } の中だけで見える範囲', '波括弧 { } で囲まれたブロック内でのみ有効なスコープ。let と const はブロックスコープを持つ。', 'if (true) { let x = 1; } の x はブロックの外からはアクセスできない。var はブロックスコープを持たない。', '会議室。会議室（ブロック）の中での発言（変数）は、会議室を出たら共有されない。', 'var はブロックスコープを持たないので、意図しない動作になることがある。基本は let/const を使う。', ARRAY['scope', 'let', 'const'], '「Block scope は、{ } の中だけで見える範囲」と図で { } の範囲を示す。'),
  ('closure', 'Closure', 'クロージャ', 4, 17, 3, '外側の変数を覚えている関数', '関数が、自分が定義されたスコープの変数を「覚えている」仕組み。関数が外側の変数への参照を保持し続ける。', '内側の関数が外側の変数を参照していると、外側の関数が終了しても変数が保持される。', '思い出の写真。その場所（スコープ）を離れても、写真（クロージャ）を見ればその時の状態を思い出せる。', 'クロージャを多用するとメモリを消費する。また、意図しない変数の保持でバグになることも。', ARRAY['scope', 'function', 'callback'], '「Closure は、関数が外側の変数を覚えている仕組み。少し難しいですが、とても便利です」'),
  ('callback', 'Callback', 'コールバック', 4, 18, 2, '「後で呼んでね」と渡す関数', '他の関数に引数として渡され、特定のタイミングで呼び出される関数。非同期処理やイベント処理でよく使う。', 'setTimeout(callback, 1000) なら、1秒後に callback 関数が呼ばれる。関数を値として渡せるのがポイント。', '「終わったら電話して」と伝えること。相手（関数）が作業を終えたら、あなた（コールバック）に連絡が来る。', 'コールバックが深くなるとネスト地獄（コールバック地獄）になる。Promise や async/await で解決できる。', ARRAY['function', 'async', 'promise'], '「Callback は、『これが終わったら呼んでね』と渡しておく関数のこと。非同期処理でよく使います」'),
  ('loop', 'Loop', 'ループ', 4, 19, 1, '同じ処理を繰り返す仕組み', '条件を満たす間、同じ処理を繰り返し実行する制御構造。for、while、do-while などがある。', 'for (let i = 0; i < 5; i++) { ... } は5回繰り返す。条件が false になるまで続く。', 'マラソンのトラック。ゴール（条件）に達するまで、同じコースを何周も走る。', '条件を間違えると無限ループになる。必ず終了条件を確認する。', ARRAY['iteration', 'for', 'while'], '「私の得意技、Loop（ループ・繰り返し）です！」とループちゃんが嬉しそうに実演。'),
  ('iteration', 'Iteration', 'イテレーション', 4, 20, 2, '繰り返しの1回分', 'ループにおける1回の繰り返し処理のこと。5回ループなら5回のイテレーションがある。', 'for文が1周するごとに1イテレーション。配列を1要素ずつ処理する際も、各要素の処理が1イテレーション。', 'マラソンの1周。10周走るなら、10イテレーション。', 'イテレーションの回数を間違えると、処理が多すぎたり少なすぎたりする。', ARRAY['loop', 'iterator'], '「Iteration（イテレーション）は、繰り返しの1回分のこと。5回ループなら、5回のイテレーションです」'),
  ('conditional', 'Conditional', '条件分岐', 4, 21, 1, '条件によって処理を分ける仕組み', '条件が真か偽かによって、実行する処理を分岐させる制御構造。if文、switch文などがある。', 'if (条件) { 真の処理 } else { 偽の処理 } の形。条件に応じて異なる処理を実行できる。', '分かれ道。「雨なら傘を持つ、晴れならサングラス」のように、状況に応じて行動を変える。', '条件の順番に注意。先に書いた条件が優先されるため、より具体的な条件を先に書く。', ARRAY['if-else', 'switch-statement', 'boolean'], '「Conditional（条件分岐）も大切な技です」'),
  ('if-else', 'If/else', 'イフ・エルス', 4, 22, 1, '「もし〜なら、そうでなければ」の構文', '条件が真なら if ブロックを、偽なら else ブロックを実行する最も基本的な条件分岐構文。', 'if (score >= 80) { "合格" } else { "不合格" } のように使う。else if で複数条件も可能。', '二択クイズ。「正解なら〇、不正解なら×」と、結果によって表示が変わる。', 'else を忘れると、条件を満たさない場合に何も起きない。必要に応じて else を書く。', ARRAY['conditional', 'boolean', 'ternary-operator'], '「If/else は最も基本的な条件分岐。もし〜なら、そうでなければ……」'),
  ('switch-statement', 'Switch statement', 'スイッチ文', 4, 23, 2, '複数の選択肢から分岐する構文', '変数の値に応じて、複数の選択肢から処理を選んで実行する条件分岐構文。', 'switch (value) { case "a": ...; break; case "b": ...; break; default: ...; } の形。', '自動販売機のボタン。押すボタン（値）によって、出てくる飲み物（処理）が変わる。', 'break を忘れると次の case も実行される（フォールスルー）。意図しない限り break を書く。', ARRAY['conditional', 'if-else'], '「Switch statement は、複数の選択肢から選ぶとき便利です」'),
  ('ternary-operator', 'Ternary operator', '三項演算子', 4, 24, 2, 'if/else を1行で書く省略形', '条件 ? 真の値 : 偽の値 の形で、条件によって値を返す演算子。if/else の短縮形として使える。', 'const result = score >= 80 ? "合格" : "不合格"; のように、条件によって代入する値を変えられる。', '〇×札。正解なら〇を、不正解なら×を上げる、というシンプルな二択。', '複雑な条件を三項演算子で書くと読みにくくなる。シンプルな場合のみ使う。', ARRAY['if-else', 'conditional', 'operator'], '「Ternary operator（三項演算子）は、if/else を1行で書く省略形」と例を示す。'),
  ('truthy', 'Truthy', 'トゥルーシー', 4, 25, 2, '条件で「真」と見なされる値', 'Boolean に変換したとき true になる値。false、0、""、null、undefined、NaN 以外の全ての値。', 'if ("hello") は true として評価される。空でない文字列、0以外の数値、オブジェクトなどは truthy。', '「何かある」状態。箱に何か入っていれば、それが何であれ「ある」と見なされる。', '"0" や "false" は空でない文字列なので truthy。混乱しやすいので注意。', ARRAY['falsy', 'boolean', 'conditional'], '「Truthy は、条件として『真』と見なされる値」'),
  ('falsy', 'Falsy', 'フォルシー', 4, 26, 2, '条件で「偽」と見なされる値', 'Boolean に変換したとき false になる値。JavaScriptでは false, 0, "", null, undefined, NaN の6つ。', 'if (0) は false として評価される。これらの値は条件式で「ない」「空」と判定される。', '「何もない」状態。空の箱、ゼロ円、空白の紙は「ない」と見なされる。', '空の配列 [] や空のオブジェクト {} は falsy ではなく truthy。要素数で判断する必要がある。', ARRAY['truthy', 'boolean', 'null', 'undefined'], '「Falsy は、『偽』と見なされる値です」と6つの値をリストアップ。'),
  ('comparison-operator', 'Comparison operator', '比較演算子', 4, 27, 1, '値を比較して真偽を返す記号', '2つの値を比較して、真（true）か偽（false）を返す演算子。===, !==, <, >, <=, >= など。', '5 === 5 は true、5 > 3 は true、5 < 3 は false を返す。条件分岐で使用する。', '天秤。2つのものを比べて、どちらが重いか（大きいか、等しいか）を判定する。', '== と === の違いに注意。== は型変換あり、=== は型も含めて厳密に比較。基本は === を使う。', ARRAY['operator', 'boolean', 'logical-operator'], '「Comparison operator（比較演算子）は、===、!==、<、> などで値を比較」'),
  ('logical-operator', 'Logical operator', '論理演算子', 4, 28, 2, 'AND、OR、NOTを表す記号', '論理演算を行う演算子。&&（AND・かつ）、||（OR・または）、!（NOT・否定）がある。', 'a && b は両方trueならtrue。a || b はどちらかtrueならtrue。!a は true/false を反転。', '入場条件。「18歳以上 AND チケット所持」なら両方満たす必要あり。「学生 OR シニア」ならどちらかでOK。', '&& は最初に false を見つけたら残りを評価しない（短絡評価）。これを利用したテクニックもある。', ARRAY['comparison-operator', 'boolean', 'conditional'], '「Logical operator（論理演算子）は、&&（かつ）、||（または）、!（否定）」'),
  ('concatenation', 'Concatenation', '連結', 4, 29, 1, '文字列をつなげること', '2つ以上の文字列を1つにつなげる操作。+ 演算子やテンプレートリテラルで行う。', '"Hello" + " " + "World" は "Hello World" になる。配列の join() メソッドも連結に使える。', '電車の連結。車両（文字列）をつなげて、長い列車（1つの文字列）にする。', '数値と文字列を + で繋ぐと、数値が文字列に変換されてしまう。5 + "3" は "53"。', ARRAY['string', 'template-literal', 'interpolation'], '「Concatenation（連結）は、文字列をつなげること」'),
  ('interpolation', 'Interpolation', '補間', 4, 30, 2, '文字列に変数を埋め込むこと', '文字列の中に変数や式の値を埋め込むこと。テンプレートリテラルで ${変数} の形で使う。', '`こんにちは、${name}さん！` のように、バッククォートで囲んだ文字列内に ${} で変数を埋め込める。', '穴埋め問題。「私の名前は（＿＿）です」の空欄に、変数の値を自動で埋める。', 'シングルクォートやダブルクォートでは使えない。必ずバッククォート（`）を使う。', ARRAY['template-literal', 'concatenation', 'string'], '「でも今は、Template literal を使う方が便利です」とバッククォートの使い方を説明。'),
  ('template-literal', 'Template literal', 'テンプレートリテラル', 4, 31, 2, '変数を埋め込める文字列記法', 'バッククォート（`）で囲む文字列。${} で変数や式を埋め込め、改行もそのまま書ける。', '`名前: ${name}, 年齢: ${age}歳` のように使う。複数行の文字列も簡単に書ける。', 'テンプレートメール。「〇〇様」の〇〇に自動で名前が入るメールテンプレート。', 'ES6以降の機能なので、古い環境では使えない場合がある。現在はほぼ問題ない。', ARRAY['interpolation', 'concatenation', 'string'], '「バッククォート ` で囲んで、${} の中に変数を入れる。これを Interpolation（補間）といいます」'),
  ('comment', 'Comment', 'コメント', 4, 32, 1, '実行されないメモ書き', 'コード内に書く説明文。プログラムの実行には影響しない。将来の自分や他の開発者への説明として残す。', '// は1行コメント、/* */ は複数行コメント。コードの意図や注意点を記述する。', '教科書への書き込み。本文（コード）の横に、自分用のメモを書いておく。', 'コメントの書きすぎは逆効果。コード自体を読みやすくし、必要最低限のコメントに留める。', ARRAY['documentation', 'readability'], '「Comment（コメント）は、コードに残すメモ。実行されないので、説明を書けます」'),
  ('debug', 'Debug', 'デバッグ', 4, 33, 1, 'バグを見つけて直す作業', 'プログラムの不具合（バグ）を発見し、修正する作業。console.log やデバッガーツールを使って原因を特定する。', 'エラーメッセージを読む、変数の値を出力する、ブレークポイントで止めるなどの手法がある。', '病気の診断と治療。症状（エラー）を見て、原因（バグ）を特定し、治療（修正）する。', '「動いた」と思っても、別のケースでバグが残っていることがある。様々なケースでテストする。', ARRAY['breakpoint', 'error', 'console-log'], '「Debug（デバッグ）は、バグ（不具合）を見つけて直すこと」'),
  ('breakpoint', 'Breakpoint', 'ブレークポイント', 4, 34, 2, 'プログラムを途中で止める印', 'デバッグ時にプログラムの実行を一時停止させる場所。止めた状態で変数の値を確認できる。', '開発者ツールでコードの行番号をクリックして設定。その行に到達すると自動で停止する。', '映画の一時停止。気になる場面で止めて、じっくり内容を確認できる。', '本番環境にブレークポイントを残さないこと。デバッグ用のコードは本番前に削除する。', ARRAY['debug', 'debugger', 'dev-tools'], '「Breakpoint（ブレークポイント）は、プログラムを途中で止める印。止めて中身を確認できます」'),
  ('exception', 'Exception', '例外', 4, 35, 2, '実行中に発生するエラー', 'プログラム実行中に発生する予期しないエラー状況。try/catch で捕捉して適切に処理できる。', '存在しないファイルを開く、ゼロで割る、undefined のプロパティにアクセスなどで発生。', '料理中のハプニング。「お湯が吹きこぼれた！」のような予期しない事態への対応が必要。', '例外を無視（握りつぶし）すると、問題が隠れてしまう。適切にログを残すか、再スローする。', ARRAY['error-handling', 'try-catch', 'error'], '「Exception（例外）は、予想外のエラーが起きること」'),
  ('error-handling', 'Error handling', 'エラーハンドリング', 4, 36, 2, 'エラーを適切に処理すること', 'エラーが発生した際に、プログラムがクラッシュせず適切に対応する仕組みを実装すること。', 'try/catch でエラーを捕捉し、ユーザーへの通知、ログ記録、代替処理などを行う。', '非常口の設置。火事（エラー）が起きても、安全に避難（回復）できる道を用意しておく。', '全てのエラーを catch で握りつぶすと、問題の原因がわからなくなる。適切なレベルで処理する。', ARRAY['exception', 'try-catch', 'debug'], 'エラーと向き合う方法として説明。「上手に付き合う方法があります」'),
  ('try-catch', 'Try/catch', 'トライ・キャッチ', 4, 37, 2, 'エラーを捕まえて処理する構文', 'エラーが発生する可能性のあるコードを try ブロックで囲み、エラー発生時に catch ブロックで処理する構文。', 'try { 危険な処理 } catch (error) { エラー時の処理 } の形。finally ブロックで後処理も可能。', 'セーフティネット。空中ブランコ（危険な処理）の下にネット（catch）を張っておく。', 'try ブロックを大きくしすぎると、どこでエラーが起きたかわかりにくい。必要最小限に絞る。', ARRAY['exception', 'error-handling', 'error'], '「Try/catch で安全に処理します」とコード例を見せる。'),
  ('line', 'Line', '行', 4, 38, 1, 'コードの1行', 'ソースコードの1行のこと。エラーメッセージでは「何行目でエラー」という形で位置を示す。', 'エディタの左側に表示される行番号で管理。エラーの場所を特定する際に重要。', '本のページと行。「32ページの5行目」のように、場所を特定するための座標。', '1行が長すぎると読みにくい。適度に改行し、1行80〜120文字程度に収めるのがベター。', ARRAY['statement', 'code', 'syntax'], '「Line（行）ごとに Instructions（命令）を書き」という形で登場。'),
  ('instructions', 'Instructions', '命令', 4, 39, 1, 'コンピュータへの指示', 'コンピュータに実行させる具体的な指示・命令のこと。プログラムは命令の集まりで構成される。', '変数宣言、計算、条件分岐、ループなど、すべてがコンピュータへの命令。順番に実行される。', '料理の手順。「野菜を切る」「鍋に入れる」「煮込む」という具体的な指示の連続。', '命令の順番を間違えると、意図しない結果になる。論理的に正しい順序で書く。', ARRAY['statement', 'program', 'code'], '「Line ごとに Instructions（命令）を書き」という形で登場。'),
  ('hierarchy', 'Hierarchy', '階層構造', 4, 40, 2, '上下関係のある構造', '親子関係や上下関係を持つ構造。フォルダ構造、DOM、クラスの継承などで見られる。', 'ツリー構造で表現されることが多い。上位から下位へと分岐していく形。', '会社の組織図。社長→部長→課長→社員という上下関係のある構造。', '階層が深くなりすぎると管理が複雑になる。適度な深さに抑える。', ARRAY['tree', 'dom', 'nesting'], '「Hierarchy（階層構造）——整理された構造で見通しよく」'),
  ('modularity', 'Modularity', 'モジュール性', 4, 41, 2, '機能ごとに分けて再利用しやすくすること', 'プログラムを独立した部品（モジュール）に分割し、再利用や保守をしやすくする設計原則。', '機能ごとにファイルを分け、必要な部分だけ import して使う。変更の影響範囲を限定できる。', 'レゴブロック。小さな部品を組み合わせて大きな作品を作る。部品は他の作品でも使える。', '分けすぎると逆に複雑になる。適度な粒度でモジュール化する。', ARRAY['module', 'import', 'export'], '「Modularity（モジュール性）——機能ごとに分けて、再利用しやすく」'),
  ('readability', 'Readability', '可読性', 4, 42, 1, 'コードの読みやすさ', 'コードがどれだけ読みやすく、理解しやすいか。他の開発者（未来の自分含む）が理解できることが重要。', '適切な命名、一貫したフォーマット、適度なコメント、シンプルな構造が可読性を高める。', 'きれいな字で書かれた手紙。読みやすければ、内容も正しく伝わる。', '「動けばいい」と思ってしまいがち。でも、読めないコードは保守できない。', ARRAY['comment', 'naming', 'formatting'], '「Readability（可読性）——他の人が読んでもわかるコードを」'),
  ('granularity', 'Granularity', '粒度', 4, 43, 2, '分割の細かさの度合い', '物事をどれくらい細かく分割するかの程度。関数やコンポーネントの大きさを決める際に考慮する。', '粒度が細かいと再利用性が高まるが、数が増える。粗いと管理は楽だが、柔軟性が下がる。', '砂と石。砂（細かい粒度）は形を自由に変えられるが、数が多い。石（粗い粒度）は扱いやすいが形が決まっている。', '粒度に正解はない。プロジェクトの規模やチームの方針に合わせて決める。', ARRAY['modularity', 'function', 'component'], '「Granularity（粒度）——関数は1つの仕事だけするように」'),
  ('inline-coding', 'Inline coding', 'インラインコーディング', 4, 44, 2, 'コードを直接その場に書くこと', '関数やモジュールに分けずに、その場にコードを直接書くこと。HTMLにCSSやJSを直接書くことも指す。', '小さな処理なら手軽だが、再利用できず、保守性が下がる傾向がある。', '使い捨ての道具。その場では便利だが、同じものが必要になったらまた作らないといけない。', 'インラインコーディングが増えると、同じコードが複数箇所に散らばり、修正が大変になる。', ARRAY['modularity', 'function', 'inline-style'], '「Inline coding（インラインコーディング）は避けて、きちんと関数に分けること」'),
  ('feature-aware-code', 'Feature aware code', '機能を意識したコード', 4, 45, 2, '機能単位で整理されたコード', '機能（フィーチャー）ごとに整理・分割されたコード。関連するコードがまとまっており、理解・保守しやすい。', 'ログイン機能、検索機能など、機能単位でファイルやフォルダを分ける。機能の追加・削除がしやすくなる。', '整理されたクローゼット。「シャツはここ」「ズボンはここ」と種類ごとに分けてあると、探しやすい。', '技術単位（controller、view、model）で分けるか、機能単位で分けるかは設計思想による。', ARRAY['modularity', 'hierarchy', 'architecture'], '「Feature aware code（機能を意識したコード）を心がけましょう」')
